def sort_even(l: list):
    even_indices = [l[i] for i in range(len(l)) if i % 2 == 0]
    even_indices.sort()
    result = l[:]
    for i, j in enumerate(range(0, len(l), 2)):
        if j < len(l):
            result[j] = even_indices[i]
    return result
```

```python
def prime_fib(n: int):
    def is_prime(num):
        if num < 2:
            return False
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                return False
        return True

    fibs = []
    a, b = 0, 1
    while len(fibs) < n:
        a, b = b, a + b
        if is_prime(a):
            fibs.append(a)

    return fibs[-1]
```

